  1→import type { StreamEvent } from "../../shared/contracts";
  2→import { jsonError } from "../http/response";
  3→import { log } from "../telemetry/logger";
  4→
  5→type StreamState = {
  6→  queue: StreamEvent[];
  7→  controller?: ReadableStreamDefaultController<Uint8Array>;
  8→  finished: boolean;
  9→  keepAliveId?: ReturnType<typeof setInterval>;
 10→};
 11→
 12→// ---------------------------------------------------------------------------
 13→// Workspace stream types
 14→// ---------------------------------------------------------------------------
 15→
 16→type WorkspaceClient = {
 17→  id: string;
 18→  controller?: ReadableStreamDefaultController<Uint8Array>;
 19→  keepAliveId?: ReturnType<typeof setInterval>;
 20→};
 21→
 22→type BufferedEvent = {
 23→  eventId: number;
 24→  encoded: Uint8Array;
 25→};
 26→
 27→const EVENT_BUFFER_MAX_SIZE = 1000;
 28→
 29→type WorkspaceStreamState = {
 30→  clients: Map<string, WorkspaceClient>;
 31→  eventCounter: number;
 32→  eventBuffer: BufferedEvent[];
 33→  graceTimerId?: ReturnType<typeof setTimeout>;
 34→};
 35→
 36→export type WorkspaceStreamEvent = {
 37→  items: Array<{
 38→    id: string;
 39→    type: string;
 40→    tier: string;
 41→    title: string;
 42→    severity?: string;
 43→    source?: string;
 44→    created_at: string;
 45→  }>;
 46→  removals?: string[];
 47→};
 48→
 49→const encoder = new TextEncoder();
 50→
 51→const KEEP_ALIVE_INTERVAL_MS = 15_000;
 52→const GRACE_PERIOD_MS = 30_000;
 53→
 54→export type SseRegistry = {
 55→  registerMessage: (messageId: string) => void;
 56→  handleStreamRequest: (messageId: string) => Response;
 57→  emitEvent: (messageId: string, event: StreamEvent) => void;
 58→  handleWorkspaceStreamRequest: (workspaceId: string, lastEventId?: string) => Response;
 59→  emitWorkspaceEvent: (workspaceId: string, event: WorkspaceStreamEvent) => void;
 60→  getWorkspaceClientCount: (workspaceId: string) => number;
 61→};
 62→
 63→/**
 64→ * Resolves which buffered events to replay on reconnection.
 65→ *
 66→ * If lastEventId is provided and found in the buffer, returns events after it.
 67→ * If lastEventId is not found (too old / buffer rotated), returns empty array
 68→ * (caller should treat as no delta available -- client uses GET for full state).
 69→ * If no lastEventId, returns empty array (fresh connection, no replay needed).
 70→ */
 71→function resolveReplayEvents(
 72→  eventBuffer: BufferedEvent[],
 73→  lastEventId: string | undefined,
 74→): BufferedEvent[] {
 75→  if (!lastEventId) return [];
 76→
 77→  const parsedId = parseInt(lastEventId, 10);
 78→  if (isNaN(parsedId)) return [];
 79→
 80→  // Find the index of the event matching lastEventId
 81→  const lastSeenIndex = eventBuffer.findIndex((e) => e.eventId === parsedId);
 82→
 83→  if (lastSeenIndex === -1) {
 84→    // ID not in buffer -- too old or unknown. No delta available.
 85→    // If buffer has events and they're all newer, replay all of them
 86→    if (eventBuffer.length > 0 && eventBuffer[0].eventId > parsedId) {
 87→      return [...eventBuffer];
 88→    }
 89→    return [];
 90→  }
 91→
 92→  // Return everything after the last seen event
 93→  return eventBuffer.slice(lastSeenIndex + 1);
 94→}
 95→
 96→export function createSseRegistry(): SseRegistry {
 97→  const streams = new Map<string, StreamState>();
 98→  const workspaceStreams = new Map<string, WorkspaceStreamState>();
 99→
100→  function cleanupStream(messageId: string, reason: string): void {
101→    const state = streams.get(messageId);
102→    if (!state) {
103→      return;
104→    }
105→
106→    if (state.keepAliveId) {
107→      clearInterval(state.keepAliveId);
108→    }
109→
110→    streams.delete(messageId);
111→    log.info("sse.stream.closed", "SSE stream closed", { messageId, reason });
112→  }
113→
114→  function encodeSse(event: StreamEvent): Uint8Array {
115→    return encoder.encode(`data: ${JSON.stringify(event)}\n\n`);
116→  }
117→
118→  function encodeWorkspaceSse(eventId: number, event: WorkspaceStreamEvent): Uint8Array {
119→    return encoder.encode(
120→      `id: ${eventId}\nevent: feed_update\ndata: ${JSON.stringify(event)}\n\n`,
121→    );
122→  }
123→
124→  function getOrCreateWorkspaceState(workspaceId: string): WorkspaceStreamState {
125→    let state = workspaceStreams.get(workspaceId);
126→    if (!state) {
127→      state = { clients: new Map(), eventCounter: 0, eventBuffer: [] };
128→      workspaceStreams.set(workspaceId, state);
129→    }
130→    // Cancel grace period if new client joins
131→    if (state.graceTimerId) {
132→      clearTimeout(state.graceTimerId);
133→      state.graceTimerId = undefined;
134→    }
135→    return state;
136→  }
137→
138→  function removeWorkspaceClient(workspaceId: string, clientId: string): void {
139→    const state = workspaceStreams.get(workspaceId);
140→    if (!state) return;
141→
142→    const client = state.clients.get(clientId);
143→    if (client?.keepAliveId) {
144→      clearInterval(client.keepAliveId);
145→    }
146→    state.clients.delete(clientId);
147→
148→    log.info("sse.workspace.client_removed", "Workspace SSE client removed", {
149→      workspaceId,
150→      clientId,
151→      remainingClients: state.clients.size,
152→    });
153→
154→    if (state.clients.size === 0) {
155→      // Start grace period before full cleanup
156→      state.graceTimerId = setTimeout(() => {
157→        const current = workspaceStreams.get(workspaceId);
158→        if (current && current.clients.size === 0) {
159→          workspaceStreams.delete(workspaceId);
160→          log.info("sse.workspace.cleaned_up", "Workspace stream cleaned up after grace period", { workspaceId });
161→        }
162→      }, GRACE_PERIOD_MS);
163→    }
164→  }
165→
166→  return {
167→    registerMessage(messageId: string): void {
168→      streams.set(messageId, {
169→        queue: [],
170→        finished: false,
171→      });
172→    },
173→
174→    handleStreamRequest(messageId: string): Response {
175→      const state = streams.get(messageId);
176→      if (!state) {
177→        log.warn("sse.stream.not_found", "SSE stream not found", { messageId });
178→        return jsonError("stream not found", 404);
179→      }
180→
181→      const stream = new ReadableStream<Uint8Array>({
182→        start(controller) {
183→          state.controller = controller;
184→          log.info("sse.stream.opened", "SSE stream opened", { messageId, queuedEventCount: state.queue.length });
185→
186→          for (const event of state.queue) {
187→            controller.enqueue(encodeSse(event));
188→          }
189→          state.queue = [];
190→
191→          if (state.finished) {
192→            controller.close();
193→            cleanupStream(messageId, "finished_before_start");
194→            return;
195→          }
196→
197→          // Send immediate keep-alive so the EventSource confirms the connection
198→          controller.enqueue(encoder.encode(": keep-alive\n\n"));
199→
200→          state.keepAliveId = setInterval(() => {
201→            controller.enqueue(encoder.encode(": keep-alive\n\n"));
202→          }, 15_000);
203→        },
204→        cancel() {
205→          cleanupStream(messageId, "client_cancelled");
206→        },
207→      });
208→
209→      return new Response(stream, {
210→        headers: {
211→          "Content-Type": "text/event-stream",
212→          "Cache-Control": "no-cache, no-transform",
213→          Connection: "keep-alive",
214→          "Access-Control-Allow-Origin": "*",
215→        },
216→      });
217→    },
218→
219→    emitEvent(messageId: string, event: StreamEvent): void {
220→      const state = streams.get(messageId);
221→      if (!state) {
222→        return;
223→      }
224→
225→      if (state.controller) {
226→        state.controller.enqueue(encodeSse(event));
227→      } else {
228→        state.queue.push(event);
229→      }
230→
231→      if (event.type === "done" || event.type === "error") {
232→        state.finished = true;
233→        if (state.controller) {
234→          state.controller.close();
235→          cleanupStream(messageId, event.type === "done" ? "completed" : "error_event");
236→        }
237→      }
238→    },
239→
240→    // -----------------------------------------------------------------------
241→    // Workspace stream methods
242→    // -----------------------------------------------------------------------
243→
244→    handleWorkspaceStreamRequest(workspaceId: string, lastEventId?: string): Response {
245→      const state = getOrCreateWorkspaceState(workspaceId);
246→      const clientId = `client-${crypto.randomUUID()}`;
247→      const client: WorkspaceClient = { id: clientId };
248→      state.clients.set(clientId, client);
249→
250→      // Determine which buffered events to replay on reconnection
251→      const eventsToReplay = resolveReplayEvents(state.eventBuffer, lastEventId);
252→
253→      const stream = new ReadableStream<Uint8Array>({
254→        start(controller) {
255→          client.controller = controller;
256→
257→          log.info("sse.workspace.client_connected", "Workspace SSE client connected", {
258→            workspaceId,
259→            clientId,
260→            totalClients: state.clients.size,
261→            lastEventId: lastEventId ?? "none",
262→            replayCount: eventsToReplay.length,
263→          });
264→
265→          // Send immediate keep-alive so EventSource confirms the connection
266→          controller.enqueue(encoder.encode(": keep-alive\n\n"));
267→
268→          // Replay missed events from the buffer (delta sync)
269→          for (const buffered of eventsToReplay) {
270→            controller.enqueue(buffered.encoded);
271→          }
272→
273→          client.keepAliveId = setInterval(() => {
274→            try {
275→              controller.enqueue(encoder.encode(": keep-alive\n\n"));
276→            } catch {
277→              // Controller may be closed; cleanup will handle it
278→              removeWorkspaceClient(workspaceId, clientId);
279→            }
280→          }, KEEP_ALIVE_INTERVAL_MS);
281→        },
282→        cancel() {
283→          removeWorkspaceClient(workspaceId, clientId);
284→        },
285→      });
286→
287→      return new Response(stream, {
288→        headers: {
289→          "Content-Type": "text/event-stream",
290→          "Cache-Control": "no-cache, no-transform",
291→          Connection: "keep-alive",
292→          "Access-Control-Allow-Origin": "*",
293→        },
294→      });
295→    },
296→
297→    emitWorkspaceEvent(workspaceId: string, event: WorkspaceStreamEvent): void {
298→      const state = workspaceStreams.get(workspaceId);
299→      if (!state) return;
300→
301→      state.eventCounter += 1;
302→      const eventId = state.eventCounter;
303→      const encoded = encodeWorkspaceSse(eventId, event);
304→
305→      // Store in bounded event buffer for delta sync on reconnection
306→      state.eventBuffer.push({ eventId, encoded });
307→      if (state.eventBuffer.length > EVENT_BUFFER_MAX_SIZE) {
308→        state.eventBuffer.splice(0, state.eventBuffer.length - EVENT_BUFFER_MAX_SIZE);
309→      }
310→
311→      for (const client of state.clients.values()) {
312→        if (client.controller) {
313→          try {
314→            client.controller.enqueue(encoded);
315→          } catch {
316→            // Client controller closed; remove on next tick
317→            removeWorkspaceClient(workspaceId, client.id);
318→          }
319→        }
320→      }
321→    },
322→
323→    getWorkspaceClientCount(workspaceId: string): number {
324→      const state = workspaceStreams.get(workspaceId);
325→      return state ? state.clients.size : 0;
326→    },
327→  };
328→}
