  1→// ---------------------------------------------------------------------------
  2→// Agent spawning — SDK adapter over @anthropic-ai/claude-agent-sdk
  3→// ---------------------------------------------------------------------------
  4→
  5→import {
  6→  buildAgentOptions,
  7→  resolveBrainCliCommand,
  8→  type AgentSpawnConfig,
  9→} from "./agent-options";
 10→import type { query as sdkQuery } from "@anthropic-ai/claude-agent-sdk";
 11→import { constants, accessSync } from "node:fs";
 12→import { delimiter, join } from "node:path";
 13→
 14→// ---------------------------------------------------------------------------
 15→// QueryFn — port type matching the SDK's query() signature
 16→// ---------------------------------------------------------------------------
 17→
 18→export type QueryFn = typeof sdkQuery;
 19→
 20→// ---------------------------------------------------------------------------
 21→// AgentHandle — returned by spawnAgent
 22→// ---------------------------------------------------------------------------
 23→
 24→export type AgentHandle = {
 25→  messages: AsyncIterable<unknown>;
 26→  abort: () => void;
 27→};
 28→
 29→// ---------------------------------------------------------------------------
 30→// SpawnAgentFn — port signature for agent spawning
 31→// ---------------------------------------------------------------------------
 32→
 33→export type SpawnAgentFn = (config: AgentSpawnConfig) => AgentHandle;
 34→
 35→type SpawnAgentDeps = {
 36→  ensureBrainCliAvailable?: () => void;
 37→};
 38→
 39→function ensureBrainCliAvailable(): void {
 40→  const command = resolveBrainCliCommand();
 41→  const isPathCommand = command.includes("/") || command.includes("\\");
 42→
 43→  if (isPathCommand) {
 44→    try {
 45→      accessSync(command, constants.X_OK);
 46→    } catch {
 47→      throw new Error(`Brain CLI is not executable at "${command}".`);
 48→    }
 49→    return;
 50→  }
 51→
 52→  const pathOverride = process.env.BRAIN_MCP_PATH_OVERRIDE;
 53→  if (pathOverride !== undefined) {
 54→    const entries = pathOverride
 55→      .split(delimiter)
 56→      .map((entry) => entry.trim())
 57→      .filter((entry) => entry.length > 0);
 58→
 59→    for (const entry of entries) {
 60→      try {
 61→        accessSync(join(entry, command), constants.X_OK);
 62→        return;
 63→      } catch {
 64→        continue;
 65→      }
 66→    }
 67→
 68→    throw new Error(`Brain CLI "${command}" was not found on BRAIN_MCP_PATH_OVERRIDE.`);
 69→  }
 70→
 71→  if (!Bun.which(command)) {
 72→    throw new Error(`Brain CLI "${command}" was not found on PATH.`);
 73→  }
 74→}
 75→
 76→// ---------------------------------------------------------------------------
 77→// createSpawnAgent — factory that injects the query function dependency
 78→// ---------------------------------------------------------------------------
 79→
 80→export function createSpawnAgent(
 81→  queryFn: QueryFn,
 82→  deps?: SpawnAgentDeps,
 83→): SpawnAgentFn {
 84→  const ensureCli = deps?.ensureBrainCliAvailable ?? ensureBrainCliAvailable;
 85→
 86→  return (config: AgentSpawnConfig): AgentHandle => {
 87→    // Fail fast before Claude starts if Brain CLI is unavailable.
 88→    ensureCli();
 89→
 90→    const abortController = new AbortController();
 91→    const opts = buildAgentOptions(config, abortController);
 92→
 93→    const stream = queryFn(opts);
 94→
 95→    return {
 96→      messages: stream,
 97→      abort: () => abortController.abort(),
 98→    };
 99→  };
100→}
101→

 1→// ---------------------------------------------------------------------------
 2→// Agent spawn configuration and options builder
 3→// ---------------------------------------------------------------------------
 4→
 5→export type AgentSpawnConfig = {
 6→  prompt: string;
 7→  workDir: string;
 8→  workspaceId: string;
 9→  brainBaseUrl: string;
10→  brainIdentityId?: string;
11→  brainEnv?: Record<string, string>;
12→  anthropicBaseUrl?: string;
13→  anthropicCustomHeaders?: string;
14→};
15→
16→export function resolveBrainCliCommand(): string {
17→  return "brain";
18→}
19→
20→// ---------------------------------------------------------------------------
21→// buildAgentOptions — pure function mapping config to SDK query params
22→// ---------------------------------------------------------------------------
23→
24→const ALLOWED_TOOLS = [
25→  "Read",
26→  "Edit",
27→  "Write",
28→  "Bash",
29→  "Glob",
30→  "Grep",
31→] as const;
32→
33→const MAX_TURNS = 200;
34→
35→export function buildAgentOptions(
36→  config: AgentSpawnConfig,
37→  abortController?: AbortController,
38→): { prompt: string; options: Record<string, unknown> } {
39→  const brainCommand = resolveBrainCliCommand();
40→  const brainMcpPathOverride = process.env.BRAIN_MCP_PATH_OVERRIDE;
41→  const settingsEnv: Record<string, string> = {
42→    ...(config.anthropicBaseUrl !== undefined ? { ANTHROPIC_BASE_URL: config.anthropicBaseUrl } : {}),
43→    ...(config.anthropicCustomHeaders !== undefined ? { ANTHROPIC_CUSTOM_HEADERS: config.anthropicCustomHeaders } : {}),
44→  };
45→
46→  return {
47→    prompt: config.prompt,
48→    options: {
49→      cwd: config.workDir,
50→      maxTurns: MAX_TURNS,
51→      allowedTools: [...ALLOWED_TOOLS],
52→      systemPrompt: { type: "preset" as const, preset: "claude_code" as const },
53→      settingSources: ["project"] as const,
54→      permissionMode: "bypassPermissions" as const,
55→      allowDangerouslySkipPermissions: true,
56→      mcpServers: {
57→        brain: {
58→          type: "stdio",
59→          command: brainCommand,
60→          args: ["mcp"],
61→          env: {
62→            BRAIN_SERVER_URL: config.brainBaseUrl,
63→            BRAIN_WORKSPACE_ID: config.workspaceId,
64→            ...(config.brainIdentityId !== undefined ? { BRAIN_IDENTITY_ID: config.brainIdentityId } : {}),
65→            ...(config.brainEnv ?? {}),
66→            ...(brainMcpPathOverride !== undefined ? { PATH: brainMcpPathOverride } : {}),
67→          },
68→        },
69→      },
70→      ...(Object.keys(settingsEnv).length > 0 ? { settings: { env: settingsEnv } } : {}),
71→      ...(abortController !== undefined ? { abortController } : {}),
72→    },
73→  };
74→}
