270→// ---------------------------------------------------------------------------
271→// Bridge handle factory
272→// ---------------------------------------------------------------------------
273→
274→export function startEventBridge(
275→  deps: EventBridgeDeps,
276→  streamId: string,
277→  sessionId: string,
278→  stallDetector?: StallDetectorHandle,
279→): EventBridgeHandle {
280→  let stopped = false;
281→
282→  const handleMessage = (message: SdkMessage): void => {
283→    if (stopped) return;
284→
285→    const streamEvents = transformSdkMessage(message, sessionId);
286→    for (const streamEvent of streamEvents) {
287→      deps.emitEvent(streamId, streamEvent);
288→    }
289→
290→    // Fire-and-forget: update last_event_at for stall detection
291→    if (streamEvents.length > 0) {
292→      deps.updateLastEventAt(sessionId).catch((err) => {
293→        log.warn("event-bridge", "Failed to update last_event_at", { sessionId, error: String(err) });
294→      });
295→    }
296→
297→    // Notify stall detector of activity
298→    if (stallDetector && streamEvents.length > 0) {
299→      stallDetector.recordActivity();
300→
301→      if (containsFileOperationStep(message)) {
302→        stallDetector.incrementStepCount();
303→      }
304→    }
305→  };
306→
307→  return {
308→    handleMessage,
309→    stop(): void {
310→      stopped = true;
311→      stallDetector?.stop();
312→    },
313→  };
314→}
