478→// ---------------------------------------------------------------------------
479→// Intent authorization helpers
480→// ---------------------------------------------------------------------------
481→
482→async function checkIntentAuthorization(
483→  surreal: Surreal,
484→  intentId: string,
485→  workspaceId: string,
486→): Promise<SessionResult<void>> {
487→  const intent = await getIntentById(surreal, intentId);
488→  if (!intent) {
489→    return {
490→      ok: false,
491→      error: {
492→        code: "INTENT_NOT_AUTHORIZED",
493→        message: `Intent ${intentId} not found`,
494→        httpStatus: 404,
495→      },
496→    };
497→  }
498→
499→  // Validate workspace scope: intent must belong to the session's workspace
500→  const intentWorkspaceId = intent.workspace.id as string;
501→  if (intentWorkspaceId !== workspaceId) {
502→    return {
503→      ok: false,
504→      error: {
505→        code: "WORKSPACE_MISMATCH",
506→        message: `Intent ${intentId} belongs to workspace "${intentWorkspaceId}", not "${workspaceId}"`,
507→        httpStatus: 403,
508→      },
509→    };
510→  }
511→
512→  const status = intent.status as IntentStatus;
513→  if (status !== "authorized") {
514→    return {
515→      ok: false,
516→      error: {
517→        code: "INTENT_NOT_AUTHORIZED",
518→        message: `Intent ${intentId} has status "${status}", expected "authorized"`,
519→        httpStatus: 403,
520→      },
521→    };
522→  }
523→
524→  return { ok: true, value: undefined as void };
525→}
526→
527→async function transitionIntentToExecuting(
528→  surreal: Surreal,
529→  intentId: string,
530→  sessionRecord: RecordId<"agent_session", string>,
531→): Promise<void> {
532→  await updateIntentStatus(surreal, intentId, "executing");
533→
534→  const intentRecord = new RecordId("intent", intentId);
535→  // NOTE: `$session` is a SurrealDB protected variable — use `$sess` instead
536→  await surreal.query(
537→    "RELATE $intent->gates->$sess SET created_at = time::now();",
538→    { intent: intentRecord, sess: sessionRecord },
539→  );
540→
541→  log.info("orchestrator.intent-gate", "Intent transitioned to executing with gates relation", {
542→    intentId,
543→    sessionId: sessionRecord.id as string,
544→  });
545→}
