  1→// ---------------------------------------------------------------------------
  2→// Types
  3→// ---------------------------------------------------------------------------
  4→
  5→export type WorktreeInfo = {
  6→  worktreePath: string;
  7→  branchName: string;
  8→};
  9→
 10→export type DiffResult = {
 11→  files: Array<{
 12→    path: string;
 13→    status: string;
 14→    additions: number;
 15→    deletions: number;
 16→  }>;
 17→  rawDiff: string;
 18→  stats: { filesChanged: number; insertions: number; deletions: number };
 19→};
 20→
 21→export type WorktreeErrorCode = "WORKTREE_EXISTS" | "GIT_ERROR";
 22→
 23→export type WorktreeError = {
 24→  code: WorktreeErrorCode;
 25→  message: string;
 26→};
 27→
 28→export type WorktreeResult<T> =
 29→  | { ok: true; value: T }
 30→  | { ok: false; error: WorktreeError };
 31→
 32→// ---------------------------------------------------------------------------
 33→// Shell executor port (injected dependency)
 34→// ---------------------------------------------------------------------------
 35→
 36→export type ShellExecResult = {
 37→  exitCode: number;
 38→  stdout: string;
 39→  stderr: string;
 40→};
 41→
 42→export type ShellExec = (
 43→  command: string,
 44→  args: string[],
 45→  cwd: string,
 46→) => Promise<ShellExecResult>;
 47→
 48→// ---------------------------------------------------------------------------
 49→// Pure helpers: path and branch construction
 50→// ---------------------------------------------------------------------------
 51→
 52→const WORKTREE_DIR = ".brain/worktrees";
 53→const BRANCH_PREFIX = "agent/";
 54→const WORKTREE_PREFIX = "agent-";
 55→
 56→export function buildWorktreePath(repoRoot: string, taskSlug: string): string {
 57→  return `${repoRoot}/${WORKTREE_DIR}/${WORKTREE_PREFIX}${taskSlug}`;
 58→}
 59→
 60→export function buildBranchName(taskSlug: string): string {
 61→  return `${BRANCH_PREFIX}${taskSlug}`;
 62→}
 63→
 64→function worktreeRelativePath(taskSlug: string): string {
 65→  return `${WORKTREE_DIR}/${WORKTREE_PREFIX}${taskSlug}`;
 66→}
 67→
 68→function taskSlugFromBranch(branchName: string): string {
 69→  return branchName.replace(BRANCH_PREFIX, "");
 70→}
 71→
 72→// ---------------------------------------------------------------------------
 73→// Error constructors
 74→// ---------------------------------------------------------------------------
 75→
 76→function worktreeExists(stderr: string): WorktreeResult<never> {
 77→  return {
 78→    ok: false,
 79→    error: {
 80→      code: "WORKTREE_EXISTS",
 81→      message: `Worktree already exists: ${stderr}`,
 82→    },
 83→  };
 84→}
 85→
 86→function gitError(stderr: string): WorktreeResult<never> {
 87→  return {
 88→    ok: false,
 89→    error: {
 90→      code: "GIT_ERROR",
 91→      message: `Git command failed: ${stderr}`,
 92→    },
 93→  };
 94→}
 95→
 96→// ---------------------------------------------------------------------------
 97→// createWorktree — creates worktree with new branch
 98→// ---------------------------------------------------------------------------
 99→
100→export async function createWorktree(
101→  exec: ShellExec,
102→  repoRoot: string,
103→  taskSlug: string,
104→): Promise<WorktreeResult<WorktreeInfo>> {
105→  const branchName = buildBranchName(taskSlug);
106→  const relativePath = worktreeRelativePath(taskSlug);
107→
108→  const result = await exec(
109→    "git",
110→    ["worktree", "add", "-b", branchName, relativePath],
111→    repoRoot,
112→  );
113→
114→  if (result.exitCode !== 0) {
115→    if (result.stderr.includes("already exists")) {
116→      return worktreeExists(result.stderr);
117→    }
118→
119→    // If the add failed for a non-"already exists" reason, a stale worktree
120→    // entry may be the cause. Prune once and retry rather than pruning
121→    // unconditionally on every call (which races with concurrent creates).
122→    await exec("git", ["worktree", "prune"], repoRoot);
123→
124→    const retry = await exec(
125→      "git",
126→      ["worktree", "add", "-b", branchName, relativePath],
127→      repoRoot,
128→    );
129→    if (retry.exitCode !== 0) {
130→      if (retry.stderr.includes("already exists")) {
131→        return worktreeExists(retry.stderr);
132→      }
133→      return gitError(retry.stderr);
134→    }
135→
136→    return {
137→      ok: true,
138→      value: {
139→        worktreePath: buildWorktreePath(repoRoot, taskSlug),
140→        branchName,
141→      },
142→    };
143→  }
144→
145→  return {
146→    ok: true,
147→    value: {
148→      worktreePath: buildWorktreePath(repoRoot, taskSlug),
149→      branchName,
150→    },
151→  };
152→}
153→
154→// ---------------------------------------------------------------------------
155→// removeWorktree — idempotent removal of worktree and branch
156→// ---------------------------------------------------------------------------
157→
158→export async function removeWorktree(
159→  exec: ShellExec,
160→  repoRoot: string,
161→  branchName: string,
162→): Promise<WorktreeResult<void>> {
163→  const taskSlug = taskSlugFromBranch(branchName);
164→  const relativePath = worktreeRelativePath(taskSlug);
165→
166→  // Remove worktree (ignore failure — idempotent)
167→  await exec(
168→    "git",
169→    ["worktree", "remove", relativePath, "--force"],
170→    repoRoot,
171→  );
172→
173→  // Delete branch (ignore failure — idempotent)
174→  await exec("git", ["branch", "-D", branchName], repoRoot);
175→
176→  return { ok: true, value: undefined };
177→}
178→
179→// ---------------------------------------------------------------------------
180→// Pure parsers: git diff output
181→// ---------------------------------------------------------------------------
182→
183→type NumstatEntry = { path: string; additions: number; deletions: number };
184→type NameStatusEntry = { path: string; status: string };
185→
186→export function parseNumstat(output: string): NumstatEntry[] {
187→  return output
188→    .split("\n")
189→    .filter((line) => line.trim() !== "")
190→    .map((line) => {
191→      const [addStr, delStr, ...pathParts] = line.split("\t");
192→      return {
193→        path: pathParts.join("\t"),
194→        additions: addStr === "-" ? 0 : parseInt(addStr, 10),
195→        deletions: delStr === "-" ? 0 : parseInt(delStr, 10),
196→      };
197→    });
198→}
199→
200→export function parseNameStatus(output: string): NameStatusEntry[] {
201→  return output
202→    .split("\n")
203→    .filter((line) => line.trim() !== "")
204→    .map((line) => {
205→      const [status, ...pathParts] = line.split("\t");
206→      return { path: pathParts.join("\t"), status };
207→    });
208→}
209→
210→const GIT_STATUS_NAMES: Record<string, string> = {
211→  A: "added",
212→  M: "modified",
213→  D: "deleted",
214→  R: "renamed",
215→  C: "copied",
216→  T: "type-changed",
217→};
218→
219→function normalizeGitStatus(raw: string): string {
220→  // git --name-status may produce R100, C080 etc. — take the leading letter.
221→  const letter = raw.charAt(0).toUpperCase();
222→  return GIT_STATUS_NAMES[letter] ?? "modified";
223→}
224→
225→export function combineDiffFileEntries(
226→  numstat: NumstatEntry[],
227→  nameStatus: NameStatusEntry[],
228→): DiffResult["files"] {
229→  const statusByPath = new Map(nameStatus.map((e) => [e.path, e.status]));
230→  return numstat.map((entry) => ({
231→    path: entry.path,
232→    status: normalizeGitStatus(statusByPath.get(entry.path) ?? "M"),
233→    additions: entry.additions,
234→    deletions: entry.deletions,
235→  }));
236→}
237→
238→// ---------------------------------------------------------------------------
239→// getDiff — generates diff between main and agent branch
240→// ---------------------------------------------------------------------------
241→
242→export async function getDiff(
243→  exec: ShellExec,
244→  repoRoot: string,
245→  branchName: string,
246→): Promise<WorktreeResult<DiffResult>> {
247→  const diffRef = `main...${branchName}`;
248→
249→  const numstatResult = await exec(
250→    "git",
251→    ["diff", "--numstat", diffRef],
252→    repoRoot,
253→  );
254→  if (numstatResult.exitCode !== 0) {
255→    return gitError(numstatResult.stderr);
256→  }
257→
258→  const nameStatusResult = await exec(
259→    "git",
260→    ["diff", "--name-status", diffRef],
261→    repoRoot,
262→  );
263→  if (nameStatusResult.exitCode !== 0) {
264→    return gitError(nameStatusResult.stderr);
265→  }
266→
267→  const rawDiffResult = await exec("git", ["diff", diffRef], repoRoot);
268→  if (rawDiffResult.exitCode !== 0) {
269→    return gitError(rawDiffResult.stderr);
270→  }
271→
272→  const numstatEntries = parseNumstat(numstatResult.stdout);
273→  const nameStatusEntries = parseNameStatus(nameStatusResult.stdout);
274→  const files = combineDiffFileEntries(numstatEntries, nameStatusEntries);
275→
276→  const stats = {
277→    filesChanged: files.length,
278→    insertions: files.reduce((sum, f) => sum + f.additions, 0),
279→    deletions: files.reduce((sum, f) => sum + f.deletions, 0),
280→  };
281→
282→  return {
283→    ok: true,
284→    value: { files, rawDiff: rawDiffResult.stdout, stats },
285→  };
286→}
