288→// ---------------------------------------------------------------------------
289→// mergeBranch — merges agent branch into current branch
290→// ---------------------------------------------------------------------------
291→
292→export async function mergeBranch(
293→  exec: ShellExec,
294→  repoRoot: string,
295→  branchName: string,
296→): Promise<WorktreeResult<void>> {
297→  const result = await exec(
298→    "git",
299→    ["merge", branchName, "--no-ff", "-m", `Merge agent work: ${branchName}`],
300→    repoRoot,
301→  );
302→
303→  if (result.exitCode !== 0) {
304→    return gitError(result.stderr);
305→  }
306→
307→  return { ok: true, value: undefined };
308→}
